#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>

#define W 800
#define H 600
#define EPS 0.001f

float dot3(float a[3], float b[3]) {
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2];
}

void sub3(float r[3], float a[3], float b[3]) {
    r[0]=a[0]-b[0]; r[1]=a[1]-b[1]; r[2]=a[2]-b[2];
}

void add3(float r[3], float a[3], float b[3]) {
    r[0]=a[0]+b[0]; r[1]=a[1]+b[1]; r[2]=a[2]+b[2];
}

void mul3f(float r[3], float a[3], float s) {
    r[0]=a[0]*s; r[1]=a[1]*s; r[2]=a[2]*s;
}

void norm3(float v[3]) {
    float l = sqrtf(v[0]*v[0] + v[1]*v[1] + v[2]*v[2]);
    if (l > 0) { v[0]/=l; v[1]/=l; v[2]/=l; }
}

// Sphere intersect
float sct(float ro[3], float rd[3], float c[3], float r, float hit[3], float n[3]) {
    float oc[3];
    sub3(oc, ro, c);
    float a = dot3(rd, rd);
    float b = 2.0f * dot3(oc, rd);
    float disc = b*b - 4.0f*a*(dot3(oc, oc) - r*r);
    if (disc < 0) return 0;
    float t = (-b - sqrtf(disc)) / (2.0f*a);
    if (t < EPS) t = (-b + sqrtf(disc)) / (2.0f*a);
    if (t < EPS) return 0;
    hit[0] = ro[0] + rd[0]*t;
    hit[1] = ro[1] + rd[1]*t;
    hit[2] = ro[2] + rd[2]*t;
    sub3(n, hit, c);
    norm3(n);
    return t;
}

// Plane intersect (y = y0)
float pct(float ro[3], float rd[3], float y0, float hit[3], float n[3]) {
    if (rd[1] >= 0) return 0;
    float t = (y0 - ro[1]) / rd[1];
    if (t < EPS) return 0;
    hit[0] = ro[0] + rd[0]*t;
    hit[1] = y0;
    hit[2] = ro[2] + rd[2]*t;
    n[0] = 0; n[1] = 1; n[2] = 0;
    return t;
}

int main() {
    float *img = (float*)malloc(W * H * 3 * sizeof(float));

    // Camera
    float ro[3] = {0, 0, -1.5f};
    float aspect = (float)W / H;

    // Sphere 1
    float sc1[3] = {0, -0.157f, 0};
    float sr1 = 0.307f;
    float scol1[3] = {0.2f, 0.04f, 0.04f};

    // Light direction (from highlight at (339, 295))
    float ld[3] = {0.5f, 0.3f, -1.0f};
    norm3(ld);

    fprintf(stderr, "Rendering...\n");

    int idx = 0;
    for (int y = 0; y < H; y++) {
        float vy = 1.0f - 2.0f * y / (H-1);  // v in [-1, 1]

        for (int x = 0; x < W; x++) {
            // Ray direction
            float ux = (2.0f * x / (W-1) - 1.0f) * aspect;
            float rd[3] = {ux, vy, 1};
            norm3(rd);

            float color[3] = {0, 0, 0};
            float tmin = 1e10f;

            // Try sphere
            float hit[3], nrm[3];
            float t = sct(ro, rd, sc1, sr1, hit, nrm);
            if (t > 0 && t < tmin) {
                tmin = t;
                // Diffuse
                float diff = fmaxf(0, dot3(nrm, ld));
                float amb = 0.1f;
                float intens = amb + diff * 0.9f;
                color[0] = scol1[0] * intens;
                color[1] = scol1[1] * intens;
                color[2] = scol1[2] * intens;

                // Specular (Blinn-Phong)
                float vdir[3];
                sub3(vdir, ro, hit);
                norm3(vdir);
                float half[3];
                add3(half, ld, vdir);
                norm3(half);
                float spec = powf(fmaxf(0, dot3(nrm, half)), 20.0f);
                color[0] += spec * 0.5f;
                color[1] += spec * 0.5f;
                color[2] += spec * 0.5f;
            }

            // Try ground plane
            float h2[3], n2[3];
            t = pct(ro, rd, -0.5f, h2, n2);
            if (t > 0 && t < tmin) {
                // Checkerboard
                int ix = (int)floorf(h2[0] * 2.0f);
                int iz = (int)floorf(h2[2] * 2.0f);
                float checker = ((ix + iz) & 1) ? 0.9f : 0.4f;

                // Fog
                float dist = sqrtf(h2[0]*h2[0] + h2[2]*h2[2]);
                float fog = fminf(1.0f, dist * 0.5f);
                float gray = checker * (1 - fog) + 0.5f * fog;
                color[0] = color[1] = color[2] = gray;
            }

            if (tmin > 1e9) {
                // Sky
                float sky_t = fmaxf(0, rd[1] * 0.5f + 0.5f);
                color[0] = 0.6f + sky_t * 0.2f;
                color[1] = 0.75f + sky_t * 0.1f;
                color[2] = 1.0f;
            }

            color[0] = fmaxf(0, fminf(1, color[0]));
            color[1] = fmaxf(0, fminf(1, color[1]));
            color[2] = fmaxf(0, fminf(1, color[2]));

            img[idx++] = color[0];
            img[idx++] = color[1];
            img[idx++] = color[2];
        }

        if (y % 60 == 0) {
            fprintf(stderr, "\rProgress: %.1f%%", 100.0f * y / H);
        }
    }

    fprintf(stderr, "\rProgress: 99.8%%\n");
    fprintf(stderr, "Rendering complete\n");

    FILE *fp = fopen("image.ppm", "w");
    fprintf(fp, "P3\n%d %d\n255\n", W, H);
    for (int i = 0; i < W * H * 3; i += 3) {
        int r = (int)(img[i] * 255.99f);
        int g = (int)(img[i+1] * 255.99f);
        int b = (int)(img[i+2] * 255.99f);
        fprintf(fp, "%d %d %d\n", r, g, b);
    }
    fclose(fp);

    fprintf(stderr, "Wrote image to image.ppm\n");
    fprintf(stderr, "Done.\n");

    free(img);
    return 0;
}
